<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <meta http-equiv="X-UA-Compatible" content="IE=edge" />
  <title>Verify your email – NutriSphere</title>
  <!--[if mso]>
  <noscript>
    <xml>
      <o:OfficeDocumentSettings>
        <o:PixelsPerInch>96</o:PixelsPerInch>
      </o:OfficeDocumentSettings>
    </xml>
  </noscript>
  <![endif]-->
</head>
<body style="margin:0;padding:0;background-color:#0A0B0A;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;-webkit-font-smoothing:antialiased;">

  <!-- Outer wrapper -->
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"
    style="background-color:#0A0B0A;min-height:100vh;">
    <tr>
      <td align="center" valign="middle" style="padding:48px 16px;">

        <!-- Glow backdrop (decorative, clipped to card area) -->
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"
          style="max-width:520px;margin:0 auto;">
          <tr>
            <td>

              <!-- Radial glow layer -->
              <div style="position:relative;">
                <div style="
                  position:absolute;
                  top:50%;
                  left:50%;
                  transform:translate(-50%,-50%);
                  width:480px;
                  height:320px;
                  background:radial-gradient(ellipse at center, rgba(127,250,136,0.13) 0%, transparent 70%);
                  filter:blur(32px);
                  pointer-events:none;
                  z-index:0;
                "></div>

                <!-- Card -->
                <div style="
                  position:relative;
                  z-index:1;
                  background:rgba(23,25,23,0.85);
                  border:1px solid rgba(255,255,255,0.08);
                  border-radius:16px;
                  box-shadow:0 8px 40px rgba(0,0,0,0.55), 0 0 0 0.5px rgba(127,250,136,0.06);
                  padding:48px 40px 40px;
                  text-align:center;
                ">

                  <!-- Logo / wordmark -->
                  <div style="margin-bottom:32px;">
                    <!-- Leaf icon -->
                    <div style="display:inline-block;margin-bottom:10px;">
                      <svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="18" cy="18" r="18" fill="rgba(127,250,136,0.12)"/>
                        <path d="M18 8C13 8 9 13 9 18C9 22 11.5 25.5 15 27C15 27 14 23 16 20C17.5 17.5 21 17 23 15C25 13 24 9 22 8C21 8 19.5 8 18 8Z"
                              fill="#7FFA88"/>
                        <path d="M16 20C14 23 15 27 15 27C17 27.5 19.5 27 21.5 25.5C19.5 25 17.5 23 16 20Z"
                              fill="#5DE066" opacity="0.7"/>
                      </svg>
                    </div>
                    <!-- App name -->
                    <div style="
                      font-size:22px;
                      font-weight:700;
                      letter-spacing:-0.3px;
                      color:#ffffff;
                      line-height:1;
                    ">
                      Nutri<span style="color:#7FFA88;">Sphere</span>
                    </div>
                  </div>

                  <!-- Divider -->
                  <div style="width:40px;height:2px;background:rgba(127,250,136,0.3);margin:0 auto 32px;border-radius:2px;"></div>

                  <!-- Heading -->
                  <h1 style="
                    margin:0 0 16px;
                    font-size:28px;
                    font-weight:700;
                    color:#7FFA88;
                    letter-spacing:-0.5px;
                    line-height:1.2;
                  ">Verify your email</h1>

                  <!-- Subtext -->
                  <p style="
                    margin:0 auto 36px;
                    font-size:15px;
                    line-height:1.65;
                    color:#B3BCB5;
                    max-width:360px;
                  ">
                    You're one step away from tracking your nutrition journey.
                    Click the button below to verify your email address.
                  </p>

                  <!-- CTA Button -->
                  <table role="presentation" cellpadding="0" cellspacing="0" border="0"
                    style="margin:0 auto 28px;">
                    <tr>
                      <td style="border-radius:8px;background:#7FFA88;box-shadow:0 0 18px rgba(127,250,136,0.4);">
                        <a href="{{ $actionUrl }}"
                           target="_blank"
                           style="
                             display:inline-block;
                             padding:14px 40px;
                             font-size:15px;
                             font-weight:700;
                             color:#0A0B0A;
                             text-decoration:none;
                             border-radius:8px;
                             letter-spacing:0.1px;
                             white-space:nowrap;
                           ">
                          Verify Email
                        </a>
                      </td>
                    </tr>
                  </table>

                  <!-- Expiry / disclaimer -->
                  <p style="
                    margin:0 auto;
                    font-size:13px;
                    line-height:1.6;
                    color:#B3BCB5;
                    max-width:360px;
                  ">
                    This link expires in <span style="color:#ffffff;font-weight:500;">24 hours</span>.
                    If you didn't create a NutriSphere account, you can safely ignore this email.
                  </p>

                  <!-- Divider -->
                  <div style="width:100%;height:1px;background:rgba(255,255,255,0.07);margin:32px 0;"></div>

                  <!-- Footer -->
                  <p style="
                    margin:0;
                    font-size:12px;
                    color:#4A524B;
                    letter-spacing:0.1px;
                  ">
                    &copy; 2025 NutriSphere. All rights reserved.
                  </p>

                </div>
                <!-- /Card -->
              </div>
              <!-- /Glow wrapper -->

            </td>
          </tr>
        </table>
        <!-- /max-width table -->

      </td>
    </tr>
  </table>
  <!-- /Outer wrapper -->

</body>
</html>
